INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('heelevel3-d1056197-moex-00029', 'heelevel3-d1056197', 'heelevel3-d1056197-moex-114-3082b5f1', 'sub-heelevel3-d1056197-02', NULL, 'single_choice', '甲為中華民國國籍人士，其與A國籍乙在A國辦理結婚登記。嗣後乙持A國結婚證書向我國駐 A國代表處申請驗證結婚證書及核發依親居留簽證。然而我國駐A國代表處卻認為，甲與乙在面 談時對於結婚重要事實陳述不一致，因此駁回乙之簽證申請。依司法實務之見解，下列敘述何者 正確？', '["甲得以自己名義提起課予義務訴訟，請求發給乙簽證", "乙不具有我國國籍，因此無法提起行政救濟", "甲得以自己名義，提起撤銷訴願及撤銷訴訟，以資救濟", "因為甲本身並非依法得申請簽證之當事人，因此無法提起行政救濟"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:50+00:00", "source_pdf_sha1": "b5b55ac548cd", "answer_pdf_sha1": "940b0a4bb83c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "207", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "僑務行政"}'::jsonb, NULL),
  ('heelevel3-d1056197-moex-00030', 'heelevel3-d1056197', 'heelevel3-d1056197-moex-114-3082b5f1', 'sub-heelevel3-d1056197-02', NULL, 'single_choice', '下列何種情形國家不負損害賠償責任？', '["甲國家公園管理機關因颱風警報，在所屬國家公園登山口公告禁止入山，乙因假期難得，仍冒 險登山而發生山難", "丙機關設立之公園鞦韆已經壞損，不堪使用，故在該鞦韆旁標示不得使用，丁仍讓其未成年之 子女戊使用，戊不幸拋飛而受有重傷", "主管機關平日未巡視公園樹木狀況，因強烈颱風來襲，致樹木倒塌壓傷路過之民眾", "土地登記機關因可歸責之事由，發生登記錯誤"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:50+00:00", "source_pdf_sha1": "b5b55ac548cd", "answer_pdf_sha1": "940b0a4bb83c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "207", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "僑務行政"}'::jsonb, NULL),
  ('heelevel3-d1056197-moex-00031', 'heelevel3-d1056197', 'heelevel3-d1056197-moex-114-3082b5f1', 'sub-heelevel3-d1056197-02', NULL, 'single_choice', '依司法實務見解，公共事業之設施穿越私有土地之地下，致逾越所有權人社會責任所應忍受範圍， 形成個人之特別犧牲時，下列敘述何者正確？', '["土地所有權人得請求需用土地人向主管機關申請徵收地上權", "所有權人之土地所有權並未受剝奪，故應忍受此一財產權社會義務的合法限制", "此屬財產權之違法侵害，當事人應請求除去侵害", "無法律則無徵收補償，若法律未有規定時，所有權人不得請求需用土地人向主管機關申請徵收"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:50+00:00", "source_pdf_sha1": "b5b55ac548cd", "answer_pdf_sha1": "940b0a4bb83c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "207", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "僑務行政"}'::jsonb, NULL),
  ('heelevel3-d1056197-moex-00032', 'heelevel3-d1056197', 'heelevel3-d1056197-moex-113-73ac96ef', 'sub-heelevel3-d1056197-01', NULL, 'essay', '2012 年 11 月 29 日聯合國大會表決，以 138 票贊成、9 票反對和 41 票
棄權，通過支持巴勒斯坦成為聯合國正式會員國的決議。2024 年5 月 10
日聯合國大會亦有表決，以 143票贊成、9 票反對和 25 票棄權，支持巴
勒斯坦成為聯合國正式會員國。兩次皆投下反對票的國家包括美國、以
色列、諾魯、帛琉、密克羅尼西亞等國。請問巴勒斯坦目前在聯合國的
地位為何？投反對票國家不支持之理由為何？聯合國大會通過這些決
議後，巴勒斯坦在聯合國內外的地位有何種改變或不變？原因為何？請
依照聯合國有關規定與國際情勢申述之。（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:50+00:00", "source_pdf_sha1": "e4c3a63b9ba6", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "305", "s": "0310", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "國際關係", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "僑務行政"}'::jsonb, NULL),
  ('heelevel3-d1056197-moex-00033', 'heelevel3-d1056197', 'heelevel3-d1056197-moex-113-73ac96ef', 'sub-heelevel3-d1056197-01', NULL, 'essay', '請闡述何謂「國際建制」（internationalregime），以及國際關係理論如何
